using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ───────────────────────── AddItem ─────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_IsReflectedInTotal()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_AccumulatesTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 3, 5.50m);

        Assert.AreEqual(26.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantities()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-001", 2, 10.00m);

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_NullSku_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem(null!, 1, 5.00m));
    }

    [TestMethod]
    public void AddItem_EmptySku_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("", 1, 5.00m));
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", 0, 5.00m));
    }

    [TestMethod]
    public void AddItem_NegativeQuantity_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", -1, 5.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("SKU-001", 1, -1.00m));
    }

    // ───────────────────────── RemoveItem ──────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _cart.AddItem("SKU-001", 2, 10.00m);
        _cart.AddItem("SKU-002", 1, 5.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_CartBecomesEmpty()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.RemoveItem("NOPE"));
    }

    [TestMethod]
    public void RemoveItem_FromEmptyCart_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.RemoveItem("SKU-001"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.RemoveItem(null!));
    }

    // ───────────────────────── CalculateTotal ──────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 2, 7.50m);
        _cart.RemoveItem("SKU-002");

        Assert.AreEqual(10.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_LargeQuantity_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-001", 1000, 0.01m);

        Assert.AreEqual(10.00m, _cart.CalculateTotal());
    }

    // ───────────────────────── ApplyCoupon ─────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m,
            "Total should be reduced after applying a valid coupon.");
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        _cart.AddItem("SKU-001", 1, 50.00m);

        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(""));
    }

    [TestMethod]
    public void ApplyCoupon_OnEmptyCart_TotalRemainsZero()
    {
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_AppliedTwice_ThrowsInvalidOperationException()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.ApplyCoupon("SAVE10"));
    }

    // ───────────────────────── Integration-style ───────────────

    [TestMethod]
    public void FullWorkflow_AddRemoveCouponTotal_ProducesExpectedResult()
    {
        _cart.AddItem("WIDGET", 2, 25.00m);
        _cart.AddItem("GADGET", 1, 50.00m);
        _cart.RemoveItem("GADGET");
        _cart.ApplyCoupon("SAVE10");

        var total = _cart.CalculateTotal();

        Assert.IsTrue(total > 0m, "Total should be positive after discount on remaining items.");
        Assert.IsTrue(total < 50.00m, "Total should be less than original price after coupon.");
    }
}

